#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_TEMP_LOW_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 52
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 50
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_OFF = 0,
    CONTROLLER_STATE_HEATING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool heater_on;
    controller_state_t state;
    bool has_valid_sensor;
    int last_temperature_c;
    uint32_t last_valid_sensor_ms;
} controller_t;

typedef struct {
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    /* Check for timeout: no valid sensor data for more than CONTROLLER_SENSOR_TIMEOUT_MS */
    if (!controller->has_valid_sensor && input.kind != CONTROLLER_INPUT_NONE) {
        output.timed_out = true;
        controller_set_safe_off(controller);
    } else if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        /* Valid temperature sensor data arrived */
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Apply control policy based on current temperature */
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temperature: turn heater ON */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Above upper band: turn heater OFF (fail-safe) */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        } else {
            /* Temperature in the working region [47, 52] */
            bool is_rising = input.temperature_c > controller->last_temperature_c;

            if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && is_rising) {
                /* Rising temperature near upper band: turn heater OFF early (anticipatory) */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Temperature not rising, hold previous safe actuator state */
                if (controller->heater_on) {
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            }
        }
    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || 
               input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        /* Sensor timeout or malformed input: fail-safe */
        controller_set_safe_off(controller);
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

