            bool is_rising = input.temperature_c > controller->last_temperature_c;

            if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && is_rising) {
                /* Rising temperature near upper band: turn heater OFF early (anticipatory) */
